const responsiveSvg = svgContent
  .replace(
    'width="1300" height="663"',
    'width="100%" height="100%" preserveAspectRatio="xMidYMid meet"'
  )
  // Country fills — solid light-purple (visual equivalent of #412460 @ 18% on #EAE8E5).
  // Using a solid color instead of fill-opacity avoids dark spots where country paths overlap.
  .replace(/fill="#E9E1E1"/g, 'fill="#CEC4D5"')
  // Country stroke gradient stops — flatten all three stops to the same light purple so
  // strokes match the fill exactly (no darker seams between countries).
  .replace(/stop-color="#F5F3F3"/g, 'stop-color="#CEC4D5"')
  .replace(/stop-color="#E1DBDB"/g, 'stop-color="#CEC4D5"')
  .replace(/stop-color="#DAD2D2"/g, 'stop-color="#CEC4D5"')
  // Wrap each pin's paths (stem + drop + white inner + gradient + highlight) in a <g>
  // so the whole pin becomes one country group — moves together, shares opacity.
  .replace(
    '<path d="M998.119 244.309V278.366"',
    '<g class="map-pin-group map-pin-cn"><path d="M998.119 244.309V278.366"'
  )
  .replace(
    '<path d="M929.813 277.66V293.996"',
    '</g><g class="map-pin-group map-pin-np"><path d="M929.813 277.66V293.996"'
  )
  .replace(
    '<path d="M1122.22 484.481V507.571"',
    '</g><g class="map-pin-group map-pin-au"><path d="M1122.22 484.481V507.571"'
  )
  .replace(
    '<path d="M907.199 314.429V329.04"',
    '</g><g class="map-pin-group map-pin-in"><path d="M907.199 314.429V329.04"'
  )
  // Close the final (India) pin group right before <defs>
  .replace('<defs>', '</g><defs>');

const PIN_ANIMATION_CSS = `
  @keyframes worldMapPinBounce {
    0%, 100% { transform: translateY(0); }
    50%      { transform: translateY(-8px); }
  }
  .map-pin-group {
    animation: worldMapPinBounce 1.4s ease-in-out infinite;
    will-change: transform, opacity;
  }
  .map-pin-cn { opacity: var(--pin-cn, 0); }
  .map-pin-np { opacity: var(--pin-np, 0); animation-delay: 0.15s; }
  .map-pin-in { opacity: var(--pin-in, 0); animation-delay: 0.30s; }
  .map-pin-au { opacity: var(--pin-au, 0); animation-delay: 0.45s; }
`;

export default function WorldMap({ className, style }) {
  return (
    <div className={className} style={{ width: "100%", height: "100%", ...style }}>
      <style>{PIN_ANIMATION_CSS}</style>
      <div
        style={{ width: "100%", height: "100%" }}
        dangerouslySetInnerHTML={{ __html: responsiveSvg }}
      />
    </div>
  );
}
